p {
  text-align: justify;
  hyphens: auto; /* Enables automatic hyphenation */
  -webkit-hyphens: auto; /* For WebKit browsers */
  -ms-hyphens: auto; /* For IE/Edge */
  hyphenate-limit-chars: 6 3 2; /* Optional: min chars in word, before hyphen, after hyphen */
}

/* Optional: Disable hyphenation for specific elements if needed */
h1, h2, h3 {
  hyphens: none;
}
